import{_ as t,o,c as n,a2 as c}from"./chunks/framework.Crpw6aS5.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"2 计算机/中间件/cyclone-dds/文档翻译/合并多个参与者.md","filePath":"2 计算机/中间件/cyclone-dds/文档翻译/合并多个参与者.md","lastUpdated":1774528642000}'),a={name:"2 计算机/中间件/cyclone-dds/文档翻译/合并多个参与者.md"};function d(i,e,r,s,l,p){return o(),n("div",null,[...e[0]||(e[0]=[c('<p>原文：<a href="https://cyclonedds.io/docs/cyclonedds/latest/config/combining-participants.html" target="_blank" rel="noreferrer">Combining multiple participants — Eclipse Cyclone DDS, 11.0.0</a></p> <p>如果单个进程创建了多个参与者，这些参与者会在 DDSI 参与者中体现出来，此时单个进程可能表现得像一个拥有众多参与者的庞大系统。若希望模拟仅存在一个参与者（该参与者拥有该节点上的所有端点），请将 <code>Internal/SquashParticipants</code> 设置为 <code>true</code>。这样做可以减少后台消息量，因为需要发送的活跃性断言大幅减少。然而，此选项也存在一些缺点：</p> <ul><li>该选项会导致工具无法显示系统拓扑结构。</li> <li>如果将多个 DCPS 域参与者合并为单个 DDSI 域参与者，与域参与者相关的活跃性监控功能将受到影响。对于“自动”活跃性设置（见 <code>dds_liveliness_kind</code>），则不存在此问题。</li></ul> <p>唯一保留的参与者的 QoS 属性，取自该进程中创建的<strong>第一个</strong>参与者。也就是说，无论其他参与者指定了什么“用户数据”，这些数据在远程节点上均不可见。</p> <p>另一种方案是将 <code>Internal/BuiltinEndpointSet</code> 设置为 <code>minimal</code>。此时，仅第一个参与者拥有这些 Writer，并在所有实体上发布数据。</p> <blockquote><p><strong>注意</strong></p> <p>此设置与其他实现并非完全兼容，因为它意味着可能会收到尚未被发现的参与者的端点发现数据。</p></blockquote>',11)])])}const u=t(a,[["render",d]]);export{m as __pageData,u as default};
